#include <stdio.h>

long long gcd(long long a, long long b) {
    while (b) { a %= b; long long t = a; a = b; b = t; }
    return a;
}

int main() {
    long long a, b;
    scanf("%lld %lld", &a, &b);
    long long g = gcd(a, b);
    printf("%lld %lld\n", g, a / g * b);
    return 0;
}

let rec gcd a b = if b = 0 then a else gcd b (a mod b)

